#!/usr/bin/env python3
"""Generate overlay-packs/maps/*.json from English source strings."""
import json
from pathlib import Path

ROOT = Path(__file__).parent
PACKS = ROOT / "overlay-packs"
MAPS = PACKS / "maps"


def load_en_strings():
    en = json.loads((PACKS / "en.json").read_text(encoding="utf-8"))
    strings = set()

    def walk(o):
        for v in o.values():
            if isinstance(v, str):
                strings.add(v)
            else:
                walk(v)

    walk(en)
    return sorted(strings)


def write_map(code: str, mapping: dict) -> None:
    MAPS.mkdir(parents=True, exist_ok=True)
    missing = [s for s in load_en_strings() if s not in mapping]
    if missing:
        raise SystemExit(f"{code}: missing {len(missing)} strings, e.g. {missing[0][:60]!r}")
    (MAPS / f"{code}.json").write_text(
        json.dumps(mapping, ensure_ascii=False, indent=2) + "\n", encoding="utf-8"
    )
    print(f"wrote {code}.json ({len(mapping)} entries)")


